DROP TABLE IF EXISTS `pub_model`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `pub_model` (
  `id` bigint NOT NULL COMMENT '主键',
  `create_user` bigint DEFAULT NULL COMMENT '创建人',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_user` bigint DEFAULT NULL COMMENT '修改人',
  `update_time` datetime DEFAULT NULL COMMENT '修改时间',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '备注',
  `is_deleted` int DEFAULT NULL COMMENT '是否已删除',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '型号名称',
  `status` int DEFAULT '0' COMMENT '状态：1启用0禁用',
  `category` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '分类：字典值',
  `sub_category` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '子分类：字典值，要通过字典子项，与catgory联动',
  `snmp_key` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '型号匹配KEY',
  `ext_config` json DEFAULT NULL COMMENT '额外配置项：json数组，让用户添加项（key value）的方式保存',
  `manufacturer_id` bigint DEFAULT NULL COMMENT '厂商id',
  `board_switch` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '是否为板卡交换机(0:否 1:是)',
  `alias` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '别名(分号隔开)',
  `tenant_id` bigint NOT NULL COMMENT '租户ID',
  `is_optical_bypass` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '0' COMMENT '光旁路设备标识：1是 0否',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='型号表';
